#include <iostream>
#include <vector>

int main() {
    int n;
    std::cin >> n;

    // dp[i][j] = number of valid sequences of length i ending with j consecutive 1s (j = 0, 1, 2)
    // dp[0][0] = 1 (empty sequence)
    std::vector<std::vector<long long>> dp(n + 1, std::vector<long long>(3, 0));
    dp[0][0] = 1;

    for (int i = 1; i <= n; i++) {
        // add a 0: any previous ending resets to 0 consecutive 1s
        dp[i][0] = dp[i-1][0] + dp[i-1][1] + dp[i-1][2];

        // add a 1 after ending with 0 consecutive 1s
        dp[i][1] = dp[i-1][0];

        // add a 1 after ending with 1 consecutive 1
        dp[i][2] = dp[i-1][1];

        // cannot add a 1 after ending with 2 consecutive 1s (would make 3)
    }

    long long result = dp[n][0] + dp[n][1] + dp[n][2];
    std::cout << result << std::endl;

    return 0;
}
